#include <sys/types.h>
#include <sys/socket.h>
#include <fcntl.h>
#include <unistd.h>
#include <vector>
#include <memory>

class FileHandle {
public:
    int fd;
    FileHandle(int fd) : fd(fd) {}
    ~FileHandle() { close(fd); }
};

std::vector<std::unique_ptr<FileHandle>> fileHandles;

void addFileHandle(int fd) {
    fileHandles.emplace_back(new FileHandle(fd));
}

void removeFileHandle(int fd) {
    for (auto it = fileHandles.begin(); it != fileHandles.end(); ++it) {
        if ((*it)->fd == fd) {
            it = fileHandles.erase(it);
            break;
        }
    }
}

void cleanup() {
    for (auto &handle : fileHandles) {
        handle.reset();
    }
    fileHandles.clear();
}